div.p:
Step 1: Bitwise Extraction
c
uint32_t vpn = (va >> 12) & 0xFFFFF;
uint32_t off = va & 0xFFF;

Step 5: Address Composition
c
pa = (pfn << 12) | offset;
// Result: 0x0007F234

Step 3: PTW Walk
c
// Locate PTE in Main Memory
uint32_t* pte_addr = pt_base + (vpn * 4);
pte_t pte = load_mem(pte_addr);
if (!pte.v) raise(PAGE_FAULT);
